1	import './CardTile.css'
2	
3	export default function CardTile({ card, onCardClick }) {
4	  function handleKeyDown(e) {
5	    if (e.key === 'Enter' || e.key === ' ') {
6	      e.preventDefault()
7	      onCardClick(card)
8	    }
9	  }
10	
11	  return (
12	    <div
13	      className="card-tile"
14	      role="button"
15	      tabIndex={0}
16	      onClick={() => onCardClick(card)}
17	      onKeyDown={handleKeyDown}
18	      aria-label={card.title}
19	    >
20	      <h3 className="card-tile-title">{card.title}</h3>
21	      <p className="card-tile-assignee">{card.assignee ?? 'Unassigned'}</p>
22	      {card.description && (
23	        <p className="card-tile-description">{card.description}</p>
24	      )}
25	    </div>
26	  )
27	}
