1	import { useEffect, useState, useRef } from 'react'
2	import { createPortal } from 'react-dom'
3	import './CardModal.css'
4	import CommentList from '../CardModal/CommentList.jsx'
5	
6	export default function CardModal({ card, onClose, onUpdate, onDelete, onAddComment = () => Promise.resolve() }) {
7	  // Edit state
8	  const [isEditingTitle, setIsEditingTitle] = useState(false)
9	  const [editTitle, setEditTitle]           = useState(card.title)
10	  const [isEditingAssignee, setIsEditingAssignee] = useState(false)
11	  const [editAssignee, setEditAssignee]     = useState(card.assignee ?? '')
12	  const [isSaving, setIsSaving]             = useState(false)
13	  const [saveError, setSaveError]           = useState(null)
14	
15	  // Delete state
16	  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false)
17	  const [isDeleting, setIsDeleting]               = useState(false)
18	
19	  // Focus refs
20	  const titleInputRef    = useRef(null)
21	  const assigneeInputRef = useRef(null)
22	
23	  // Focus effects
24	  useEffect(() => {
25	    if (isEditingTitle && titleInputRef.current) titleInputRef.current.focus()
26	  }, [isEditingTitle])
27	
28	  useEffect(() => {
29	    if (isEditingAssignee && assigneeInputRef.current) assigneeInputRef.current.focus()
30	  }, [isEditingAssignee])
31	
32	  // Escape key handler — replaces the original handler
33	  useEffect(() => {
34	    function onKey(e) {
35	      if (e.key !== 'Escape') return
36	      if (isEditingTitle) {
37	        setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null)
38	      } else if (isEditingAssignee) {
39	        setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
40	      } else {
41	        onClose()
42	      }
43	    }
44	    document.addEventListener('keydown', onKey)
45	    return () => document.removeEventListener('keydown', onKey)
46	  }, [onClose, isEditingTitle, isEditingAssignee, card.title, card.assignee])
47	
48	  // Save handlers
49	  async function handleSaveTitle() {
50	    if (editTitle.trim() === '') {
51	      setSaveError('Title is required')
52	      return
53	    }
54	    setIsSaving(true); setSaveError(null)
55	    try {
56	      await onUpdate(card.id, { title: editTitle })
57	      setIsEditingTitle(false)
58	    } catch (err) {
59	      setSaveError(err.message)
60	    } finally {
61	      setIsSaving(false)
62	    }
63	  }
64	
65	  async function handleSaveAssignee() {
66	    setIsSaving(true); setSaveError(null)
67	    try {
68	      await onUpdate(card.id, { assignee: editAssignee === '' ? null : editAssignee })
69	      setIsEditingAssignee(false)
70	    } catch (err) {
71	      setSaveError(err.message)
72	    } finally {
73	      setIsSaving(false)
74	    }
75	  }
76	
77	  async function handleConfirmDelete() {
78	    setIsDeleting(true); setSaveError(null)
79	    try {
80	      await onDelete(card.id)
81	      onClose()
82	    } catch (err) {
83	      setSaveError(err.message)
84	      setShowDeleteConfirm(false)
85	    } finally {
86	      setIsDeleting(false)
87	    }
88	  }
89	
90	  return createPortal(
91	    <div className="modal-overlay" onClick={onClose}>
92	      <div
93	        className="modal-content"
94	        role="dialog"
95	        aria-modal="true"
96	        aria-label={card.title}
97	        onClick={e => e.stopPropagation()}
98	      >
99	        {/* 1. Close button */}
100	        <button className="modal-close" onClick={onClose} aria-label="Close">
101	          ✕
102	        </button>
103	
104	        {/* 2. Title field (editable) */}
105	        {isEditingTitle ? (
106	          <div className="modal-field-edit">
107	            <input
108	              ref={titleInputRef}
109	              aria-label="Title"
110	              value={editTitle}
111	              onChange={e => setEditTitle(e.target.value)}
112	              onKeyDown={e => { if (e.key === 'Enter') handleSaveTitle() }}
113	            />
114	            <button aria-label="Save" onClick={handleSaveTitle} disabled={isSaving}>
115	              {isSaving ? 'Saving…' : 'Save'}
116	            </button>
117	            <button
118	              aria-label="Cancel"
119	              disabled={isSaving}
120	              onClick={() => { setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null) }}
121	            >
122	              Cancel
123	            </button>
124	          </div>
125	        ) : (
126	          <div className="modal-field-view">
127	            <h2 className="modal-title">{card.title}</h2>
128	            <button
129	              aria-label="Edit title"
130	              onClick={() => {
131	                setIsEditingTitle(true); setEditTitle(card.title)
132	                // Mutual exclusivity: close assignee edit if open
133	                setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
134	              }}
135	            >
136	              Edit
137	            </button>
138	          </div>
139	        )}
140	
141	        {/* 3. Assignee field (editable) */}
142	        {isEditingAssignee ? (
143	          <div className="modal-field-edit">
144	            <input
145	              ref={assigneeInputRef}
146	              aria-label="Assignee"
147	              value={editAssignee}
148	              onChange={e => setEditAssignee(e.target.value)}
149	              onKeyDown={e => { if (e.key === 'Enter') handleSaveAssignee() }}
150	            />
151	            <button aria-label="Save" onClick={handleSaveAssignee} disabled={isSaving}>
152	              {isSaving ? 'Saving…' : 'Save'}
153	            </button>
154	            <button
155	              aria-label="Cancel"
156	              disabled={isSaving}
157	              onClick={() => { setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null) }}
158	            >
159	              Cancel
160	            </button>
161	          </div>
162	        ) : (
163	          <div className="modal-field-view">
164	            <p className="modal-assignee">
165	              <strong>Assignee:</strong> {card.assignee ?? 'Unassigned'}
166	            </p>
167	            <button
168	              aria-label="Edit assignee"
169	              onClick={() => {
170	                setIsEditingAssignee(true); setEditAssignee(card.assignee ?? '')
171	                // Mutual exclusivity: close title edit if open
172	                setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null)
173	              }}
174	            >
175	              Edit
176	            </button>
177	          </div>
178	        )}
179	
180	        {/* 4. Description (read-only) */}
181	        <p className="modal-description">{card.description ?? 'No description'}</p>
182	
183	        {/* 5. Error alert */}
184	        {saveError && <p role="alert" className="modal-error">{saveError}</p>}
185	
186	        {/* 6. Comments section */}
187	        <CommentList
188	          comments={card.comments}
189	          onAddComment={(data) => onAddComment(card.id, data)}
190	        />
191	
192	        {/* 7. Delete button / confirmation */}
193	        {showDeleteConfirm ? (
194	          <div className="modal-delete-confirm" role="region" aria-label="Delete confirmation">
195	            <p>Are you sure you want to delete this card?</p>
196	            <button
197	              aria-label="Confirm delete"
198	              onClick={handleConfirmDelete}
199	              disabled={isDeleting}
200	            >
201	              {isDeleting ? 'Deleting…' : 'Confirm delete'}
202	            </button>
203	            <button
204	              aria-label="Keep card"
205	              onClick={() => setShowDeleteConfirm(false)}
206	              disabled={isDeleting}
207	            >
208	              Keep card
209	            </button>
210	          </div>
211	        ) : (
212	          <button
213	            className="modal-delete"
214	            aria-label="Delete"
215	            onClick={() => setShowDeleteConfirm(true)}
216	          >
217	            Delete
218	          </button>
219	        )}
220	      </div>
221	    </div>,
222	    document.body
223	  )
224	}
