1	import { Router } from 'express';
2	import { createCard, updateCard, deleteCard, moveCard, NotFoundError } from '../db/queries.js';
3	import { broadcast } from '../ws/broadcaster.js';
4	
5	const router = Router();
6	
7	// POST /api/cards
8	router.post('/cards', (req, res, next) => {
9	  const { title, assignee, column, description } = req.body ?? {};
10	  if (!title) {
11	    return res.status(400).json({ error: 'title is required' });
12	  }
13	  try {
14	    const card = createCard({ title, assignee, column, description });
15	    try { broadcast('card:created', card); } catch { /* isolate broadcast errors */ }
16	    return res.status(201).json(card);
17	  } catch (err) {
18	    next(err);
19	  }
20	});
21	
22	// PATCH /api/cards/:id
23	const CARD_UPDATE_ALLOWED = ['title', 'assignee', 'column', 'description', 'position'];
24	router.patch('/cards/:id', (req, res, next) => {
25	  const updateData = req.body ?? {};
26	  try {
27	    const card = updateCard(req.params.id, updateData);
28	    // Only broadcast when at least one recognized field was in the request body,
29	    // meaning updateCard actually performed a DB write. An empty or unrecognized-only
30	    // body causes updateCard to return the card unchanged (no DB write), so no broadcast.
31	    if (Object.keys(updateData).some(k => CARD_UPDATE_ALLOWED.includes(k))) {
32	      try { broadcast('card:updated', card); } catch { /* isolate broadcast errors */ }
33	    }
34	    return res.status(200).json(card);
35	  } catch (err) {
36	    if (err instanceof NotFoundError) {
37	      return res.status(404).json({ error: err.message });
38	    }
39	    next(err);
40	  }
41	});
42	
43	// DELETE /api/cards/:id
44	router.delete('/cards/:id', (req, res, next) => {
45	  try {
46	    deleteCard(req.params.id);
47	    try { broadcast('card:deleted', { id: req.params.id }); } catch { /* isolate */ }
48	    return res.status(204).send();
49	  } catch (err) {
50	    if (err instanceof NotFoundError) {
51	      return res.status(404).json({ error: err.message });
52	    }
53	    next(err);
54	  }
55	});
56	
57	// PATCH /api/cards/:id/move
58	router.patch('/cards/:id/move', (req, res, next) => {
59	  const { column, position } = req.body ?? {};
60	  if (!column || position === undefined || position === null) {
61	    return res.status(400).json({ error: 'column and position are required' });
62	  }
63	  try {
64	    const card = moveCard(req.params.id, column, position);
65	    try { broadcast('card:moved', card); } catch { /* isolate */ }
66	    return res.status(200).json(card);
67	  } catch (err) {
68	    if (err instanceof NotFoundError) {
69	      return res.status(404).json({ error: err.message });
70	    }
71	    next(err);
72	  }
73	});
74	
75	export default router;
