1	import Database from 'better-sqlite3';
2	import { v4 as uuidv4 } from 'uuid';
3	import { readFileSync, mkdirSync } from 'node:fs';
4	import { fileURLToPath } from 'node:url';
5	import { resolve, dirname } from 'node:path';
6	
7	const __dirname = dirname(fileURLToPath(import.meta.url));
8	
9	// --- Custom Errors ---
10	export class NotFoundError extends Error {
11	  constructor(msg) { super(msg); this.name = 'NotFoundError'; }
12	}
13	export class DatabaseError extends Error {
14	  constructor(msg) { super(msg); this.name = 'DatabaseError'; }
15	}
16	export class ForeignKeyError extends DatabaseError {
17	  constructor(msg) { super(msg); this.name = 'ForeignKeyError'; }
18	}
19	
20	// --- Module-level singletons ---
21	let db = null;
22	let stmts = {};
23	
24	export function getDb() { return db; }
25	
26	// --- initDb ---
27	export function initDb(dbPath = 'data/kanban.db') {
28	  const resolvedPath = dbPath === ':memory:' ? ':memory:' : resolve(process.cwd(), dbPath);
29	  if (dbPath !== ':memory:') {
30	    mkdirSync(dirname(resolvedPath), { recursive: true });
31	  }
32	  db = new Database(resolvedPath);
33	  db.pragma('journal_mode = WAL');
34	  db.pragma('foreign_keys = ON');
35	  const sql = readFileSync(resolve(__dirname, 'migrations', '001_init.sql'), 'utf8');
36	  db.exec(sql);
37	  _prepareStatements();
38	  return db;
39	}
40	
41	function _prepareStatements() {
42	  stmts.getAllCards     = db.prepare('SELECT * FROM cards ORDER BY "column", position');
43	  stmts.getAllComments  = db.prepare('SELECT * FROM comments ORDER BY created_at');
44	  stmts.insertCard     = db.prepare(
45	    'INSERT INTO cards (id, title, assignee, "column", position, description, created_at) VALUES (@id, @title, @assignee, @column, @position, @description, @created_at)'
46	  );
47	  stmts.getCardById    = db.prepare('SELECT * FROM cards WHERE id = ?');
48	  stmts.maxPosInCol    = db.prepare('SELECT MAX(position) AS maxPos FROM cards WHERE "column" = ?');
49	  stmts.deleteCard     = db.prepare('DELETE FROM cards WHERE id = ?');
50	  stmts.insertComment  = db.prepare(
51	    'INSERT INTO comments (id, card_id, author, content, created_at) VALUES (@id, @card_id, @author, @content, @created_at)'
52	  );
53	  stmts.getCommentById = db.prepare('SELECT * FROM comments WHERE id = ?');
54	  stmts.getSiblings    = db.prepare(
55	    'SELECT id, position FROM cards WHERE "column" = ? AND id != ? ORDER BY position'
56	  );
57	  stmts.updateCardPos  = db.prepare(
58	    'UPDATE cards SET "column" = @column, position = @position WHERE id = @id'
59	  );
60	}
61	
62	export function closeDb() {
63	  if (db) { db.close(); db = null; stmts = {}; }
64	}
65	
66	// --- getCards ---
67	export function getCards() {
68	  const cards = stmts.getAllCards.all();
69	  const comments = stmts.getAllComments.all();
70	  const byCard = {};
71	  for (const c of comments) {
72	    (byCard[c.card_id] ??= []).push(c);
73	  }
74	  return cards.map(card => ({ ...card, comments: byCard[card.id] ?? [] }));
75	}
76	
77	// --- createCard ---
78	export function createCard(data) {
79	  const { title, assignee = null, column = 'ready', description = null } = data;
80	  const id = uuidv4();
81	  const created_at = Date.now();
82	  const { maxPos } = stmts.maxPosInCol.get(column);
83	  const position = maxPos === null ? 1.0 : maxPos + 1.0;
84	  stmts.insertCard.run({ id, title, assignee, column, position, description, created_at });
85	  return stmts.getCardById.get(id);
86	}
87	
88	// --- updateCard ---
89	export function updateCard(id, data) {
90	  const allowed = ['title', 'assignee', 'column', 'description', 'position'];
91	  const fields = Object.keys(data).filter(k => allowed.includes(k));
92	  if (fields.length === 0) {
93	    const card = stmts.getCardById.get(id);
94	    if (!card) throw new NotFoundError(`Card not found: ${id}`);
95	    return card;
96	  }
97	  const setClause = fields.map(f => `"${f}" = @${f}`).join(', ');
98	  const result = db.prepare(`UPDATE cards SET ${setClause} WHERE id = @id`).run({ ...data, id });
99	  if (result.changes === 0) throw new NotFoundError(`Card not found: ${id}`);
100	  return stmts.getCardById.get(id);
101	}
102	
103	// --- deleteCard ---
104	export function deleteCard(id) {
105	  const result = stmts.deleteCard.run(id);
106	  if (result.changes === 0) throw new NotFoundError(`Card not found: ${id}`);
107	  return true;
108	}
109	
110	// --- moveCard ---
111	export function moveCard(id, column, position) {
112	  const card = stmts.getCardById.get(id);
113	  if (!card) throw new NotFoundError(`Card not found: ${id}`);
114	
115	  const doMove = db.transaction(() => {
116	    const siblings = stmts.getSiblings.all(column, id);
117	    // siblings: sorted by position, excludes the moved card itself
118	
119	    if (siblings.length === 0) {
120	      stmts.updateCardPos.run({ column, position: 1.0, id });
121	    } else if (position <= 0) {
122	      stmts.updateCardPos.run({ column, position: siblings[0].position / 2, id });
123	    } else if (position >= siblings.length) {
124	      stmts.updateCardPos.run({ column, position: siblings[siblings.length - 1].position + 1.0, id });
125	    } else {
126	      const before = siblings[position - 1].position;
127	      const after  = siblings[position].position;
128	      const gap    = after - before;
129	
130	      if (gap >= 0.001) {
131	        stmts.updateCardPos.run({ column, position: (before + after) / 2, id });
132	      } else {
133	        // Renormalize: splice moved card into siblings at the target index, then
134	        // assign clean integer positions (1.0, 2.0, 3.0, ...) to all cards in column
135	        const renorm = db.prepare('UPDATE cards SET "column" = ?, position = ? WHERE id = ?');
136	        const newOrder = [
137	          ...siblings.slice(0, position),
138	          { id },
139	          ...siblings.slice(position),
140	        ];
141	        newOrder.forEach((s, i) => renorm.run(column, i + 1.0, s.id));
142	      }
143	    }
144	
145	    return stmts.getCardById.get(id);
146	  });
147	
148	  return doMove();
149	}
150	
151	// --- createComment ---
152	export function createComment(cardId, data) {
153	  const { author, content } = data;
154	  const id = uuidv4();
155	  const created_at = Date.now();
156	  try {
157	    stmts.insertComment.run({ id, card_id: cardId, author, content, created_at });
158	  } catch (err) {
159	    if (err.code === 'SQLITE_CONSTRAINT_FOREIGNKEY') {
160	      throw new ForeignKeyError(`Card not found: ${cardId}`);
161	    }
162	    throw new DatabaseError(err.message);
163	  }
164	  return stmts.getCommentById.get(id);
165	}
