133	                setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null)
134	              }}
135	            >
136	              Edit
137	            </button>
138	          </div>
139	        )}
140	
141	        {/* 3. Assignee field (editable) */}
